import Link from "next/link";import {ArrowLeft,CheckCircle2,ClipboardCheck} from "lucide-react";import {redirect} from "next/navigation";import {saveVendorProfile} from "@/app/(platform)/vendor/profile/actions";import {getRoleHome} from "@/src/lib/auth/routing";import {requireUser} from "@/src/lib/auth/session";import {createSupabaseServerClient} from "@/src/lib/supabase/server";
const field="min-h-11 w-full rounded-xl border border-slate-200 bg-white px-3 text-base outline-none focus:border-emerald-600 focus:ring-2 focus:ring-emerald-100";
export default async function VendorProfilePage({searchParams}:{searchParams:Promise<{result?:string}>}){const user=await requireUser();const org=user.memberships.find(x=>x.organizationType==="vendor"&&["owner","admin"].includes(x.role));if(!org)redirect(getRoleHome(user));const supabase=await createSupabaseServerClient();const [{data:organization},{data:profile},{data:categories},{data:services},{data:areas}]=await Promise.all([supabase.from("organizations").select("name,phone,website_url,status").eq("id",org.organizationId).single(),supabase.from("vendor_profiles").select("description,public_email,approval_status,lifecycle_status,publication_status,public_display_consent").eq("organization_id",org.organizationId).single(),supabase.from("vendor_category_assignments").select("vendor_categories(name)").eq("vendor_organization_id",org.organizationId),supabase.from("vendor_service_offerings").select("vendor_services(name)").eq("vendor_organization_id",org.organizationId).eq("is_active",true),supabase.from("vendor_service_cities").select("cities(name,state_code)").eq("vendor_organization_id",org.organizationId).eq("is_active",true)]);const result=(await searchParams).result;const category=(categories?.[0]?.vendor_categories as unknown as {name:string}|null)?.name??"";const serviceText=(services??[]).map(x=>(x.vendor_services as unknown as {name:string}|null)?.name).filter(Boolean).join("\n");const areaText=(areas??[]).map(x=>{const city=x.cities as unknown as {name:string;state_code:string}|null;return city?`${city.name}, ${city.state_code}`:null}).filter(Boolean).join("\n");return <div><Link href="/vendor" className="inline-flex items-center text-sm font-bold text-slate-500"><ArrowLeft className="mr-2 size-4"/>Vendor dashboard</Link><div className="mt-6 grid gap-6 lg:grid-cols-[1fr_18rem]"><main className="rounded-[2rem] border border-slate-200 bg-white p-6 shadow-sm sm:p-10"><p className="text-xs font-black uppercase tracking-[.16em] text-emerald-700">Tier-independent onboarding</p><h1 className="mt-3 text-4xl font-semibold tracking-[-.04em]">Complete your marketplace profile.</h1><p className="mt-4 text-sm leading-6 text-slate-600">Payment does not publish a listing. Every paid tier must provide the required business, category, service, and service-area details and complete review.</p>{result==="saved"?<p role="status" className="mt-5 rounded-xl bg-emerald-50 p-4 text-sm font-semibold text-emerald-800">Profile saved and publication eligibility re-evaluated.</p>:result?<p role="alert" className="mt-5 rounded-xl bg-rose-50 p-4 text-sm font-semibold text-rose-800">Review every field. Service areas must use “City, ST”.</p>:null}<form action={saveVendorProfile} className="mt-8 grid gap-5 sm:grid-cols-2"><label className="sm:col-span-2"><span className="mb-1.5 block text-sm font-bold">Business name</span><input className={field} name="businessName" required minLength={2} maxLength={160} defaultValue={organization?.name}/></label><label className="sm:col-span-2"><span className="mb-1.5 block text-sm font-bold">Business description</span><textarea className={`${field} min-h-32 py-3`} name="description" required minLength={40} maxLength={2000} defaultValue={profile?.description??""}/></label><label><span className="mb-1.5 block text-sm font-bold">Public email</span><input className={field} name="publicEmail" type="email" required defaultValue={profile?.public_email??user.email}/></label><label><span className="mb-1.5 block text-sm font-bold">Public phone</span><input className={field} name="phone" type="tel" required defaultValue={organization?.phone??""}/></label><label className="sm:col-span-2"><span className="mb-1.5 block text-sm font-bold">Website</span><input className={field} name="website" type="url" defaultValue={organization?.website_url??""}/></label><label className="sm:col-span-2"><span className="mb-1.5 block text-sm font-bold">Primary category</span><input className={field} name="primaryCategory" required defaultValue={category} placeholder="Plumbing"/></label><label><span className="mb-1.5 block text-sm font-bold">Services offered</span><textarea className={`${field} min-h-36 py-3`} name="services" required defaultValue={serviceText} placeholder={"Drain cleaning\nWater heater repair"}/><span className="mt-1 block text-xs text-slate-400">One service per line</span></label><label><span className="mb-1.5 block text-sm font-bold">Service areas</span><textarea className={`${field} min-h-36 py-3`} name="serviceAreas" required defaultValue={areaText} placeholder={"Rockford, IL\nLoves Park, IL"}/><span className="mt-1 block text-xs text-slate-400">One “City, ST” per line</span></label><label className="flex gap-3 rounded-xl bg-slate-50 p-4 text-sm sm:col-span-2"><input name="publicDisplayConsent" type="checkbox" required defaultChecked={profile?.public_display_consent}/><span>I authorize display of the approved profile information in the public marketplace.</span></label><button className="min-h-12 rounded-full bg-slate-950 px-6 text-sm font-black text-white sm:col-span-2">Save and evaluate profile</button></form></main><aside className="rounded-2xl bg-slate-950 p-6 text-white lg:self-start"><ClipboardCheck className="size-6 text-emerald-400"/><h2 className="mt-5 font-bold">Current lifecycle</h2><dl className="mt-4 space-y-3 text-xs"><div><dt className="text-slate-400">Profile</dt><dd className="mt-1 font-bold capitalize">{profile?.lifecycle_status?.replaceAll("_"," ")}</dd></div><div><dt className="text-slate-400">Approval</dt><dd className="mt-1 font-bold capitalize">{profile?.approval_status?.replaceAll("_"," ")}</dd></div><div><dt className="text-slate-400">Publication</dt><dd className="mt-1 font-bold capitalize">{profile?.publication_status}</dd></div></dl>{profile?.publication_status==="published"?<p className="mt-5 flex gap-2 text-xs text-emerald-300"><CheckCircle2 className="size-4"/>Your listing is public.</p>:<p className="mt-5 text-xs leading-5 text-slate-300">A paid membership, complete profile, approval, and an unsuspended organization are all required.</p>}</aside></div></div>}
